import (
	"bufio"
	"context"
	"crypto/sha256"
	"encoding/json"
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/tools/kapow/internal/config"
	"github.com/ketang/kapow/tools/kapow/internal/deadlines"
	"github.com/ketang/kapow/tools/kapow/internal/fetch"
	"github.com/ketang/kapow/tools/kapow/internal/namematch"
)

func init() {
	Register(&bigfutureImporter{})
}

type bigfutureImporter struct {
	year        int
	concurrency int
	rateLimit   time.Duration
	slugFile    string
}

func (b *bigfutureImporter) Name() string         { return "deadlines-bigfuture" }
func (b *bigfutureImporter) Description() string   { return "Import admissions deadlines from BigFuture" }
func (b *bigfutureImporter) Dependencies() []string { return []string{"nces"} }

func (b *bigfutureImporter) RegisterFlags(fs *flag.FlagSet) {
	fs.IntVar(&b.year, "year", time.Now().Year(), "admission cycle year (e.g. 2026 for Fall 2026)")
	fs.IntVar(&b.concurrency, "concurrency", 3, "max concurrent fetches")
	fs.DurationVar(&b.rateLimit, "rate-limit", 500*time.Millisecond, "minimum delay between requests")
	fs.StringVar(&b.slugFile, "slug-file", "", "optional file with one slug per line (overrides DB names)")
}

// slugEntry pairs a BigFuture slug with its source institution name and unit ID.
type slugEntry struct {
	slug   string
	name   string
	unitID string
}

func (b *bigfutureImporter) Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, _ *fetch.Fetcher) error {
	if cfg.DryRun {
		slog.Info("deadlines-bigfuture: dry-run mode — would fetch BigFuture pages",
			"year", b.year, "concurrency", b.concurrency, "rate_limit", b.rateLimit)
		return nil
	}

	// Load name matcher from DB.
	matcher, err := namematch.Load(ctx, pool)
	if err != nil {
		return fmt.Errorf("deadlines-bigfuture: load matcher: %w", err)
	}

	// Build slug list.
	slugs, err := b.buildSlugList(ctx, pool)
	if err != nil {
		return fmt.Errorf("deadlines-bigfuture: build slug list: %w", err)
	}
	slog.Info("deadlines-bigfuture: slug list built", "count", len(slugs))

	// Process each slug with rate limiting.
	client := &http.Client{Timeout: 30 * time.Second}
	var stats bigfutureStats

	for i, entry := range slugs {
		if err := ctx.Err(); err != nil {
			return fmt.Errorf("deadlines-bigfuture: cancelled: %w", err)
		}

		// Rate limit: wait before each request (except the first).
		if i > 0 {
			select {
			case <-ctx.Done():
				return fmt.Errorf("deadlines-bigfuture: cancelled: %w", ctx.Err())
			case <-time.After(b.rateLimit):
			}
		}

		if err := b.processSlug(ctx, pool, client, matcher, entry, &stats); err != nil {
			slog.Warn("deadlines-bigfuture: slug failed",
				"slug", entry.slug, "name", entry.name, "error", err)
			stats.errors++
			continue
		}
	}

	slog.Info("deadlines-bigfuture: complete",
		"total", len(slugs),
		"matched", stats.matched,
		"unmatched", stats.unmatched,
		"errors", stats.errors,
		"skipped_no_data", stats.skippedNoData,
	)

	return nil
}

// bigfutureStats tracks processing statistics.
type bigfutureStats struct {
	matched       int
	unmatched     int
	errors        int
	skippedNoData int
}

// processSlug fetches a single BigFuture page, parses it, matches it to an
// institution, and upserts the deadline data.
func (b *bigfutureImporter) processSlug(
	ctx context.Context,
	pool *pgxpool.Pool,
	client *http.Client,
	matcher *namematch.Matcher,
	entry slugEntry,
	stats *bigfutureStats,
) error {
	// Fetch page.
	html, statusCode, err := deadlines.FetchPage(ctx, client, entry.slug)
	if err != nil {
		return err
	}

	// Parse __NEXT_DATA__.
	bf, err := deadlines.ParseNextData(html)
	if err != nil {
		return fmt.Errorf("parse %s: %w", entry.slug, err)
	}

	// Resolve unit ID: prefer IPEDS ID match, then entry's pre-resolved unitID,
	// then name match.
	unitID := resolveUnitID(bf, matcher, entry)
	if unitID == "" {
		slog.Debug("deadlines-bigfuture: unmatched",
			"slug", entry.slug, "name", entry.name, "ipeds", bf.IPEDSId)
		stats.unmatched++
		return nil
	}
	stats.matched++

	// Convert to deadline data.
	dd := deadlines.ToDeadlineData(bf, b.year)

	if len(dd.Plans) == 0 {
		slog.Debug("deadlines-bigfuture: no plans extracted", "slug", entry.slug, "unit_id", unitID)
		stats.skippedNoData++
		return nil
	}

	// Store scraped page.
	hash := contentHash(html)
	status16 := int16(statusCode)
	apiResp, _ := json.Marshal(bf)
	spParams := &deadlines.ScrapedPageParams{
		UnitID:      unitID,
		PageType:    "bigfuture",
		URL:         deadlines.BigFutureURL(entry.slug),
		ContentText: "", // We store the structured data in APIResponse instead.
		ContentHTML: nil,
		APIResponse: apiResp,
		HTTPStatus:  &status16,
		ContentHash: &hash,
	}
	if _, err := deadlines.StoreScrapedPage(ctx, pool, spParams); err != nil {
		slog.Warn("deadlines-bigfuture: store scraped page failed",
			"slug", entry.slug, "unit_id", unitID, "error", err)
		// Non-fatal: continue to upsert deadline data.
	}

	// Upsert deadline data.
	if err := deadlines.UpsertDeadlines(ctx, pool, unitID, b.year, dd); err != nil {
		return fmt.Errorf("upsert %s/%s: %w", unitID, entry.slug, err)
	}

	slog.Debug("deadlines-bigfuture: upserted",
		"slug", entry.slug, "unit_id", unitID, "plans", len(dd.Plans))

	return nil
}

// resolveUnitID attempts to match a BigFuture result to a unit ID using multiple
// strategies: IPEDS ID from the page data, pre-resolved unit ID from the slug
// entry, or name matching on the slug.
func resolveUnitID(bf *deadlines.BigFutureData, matcher *namematch.Matcher, entry slugEntry) string {
	// Strategy 1: Use IPEDS ID from BigFuture data if available.
	if bf.IPEDSId != "" {
		// IPEDS IDs are unit IDs in our system.
		return bf.IPEDSId
	}

	// Strategy 2: Pre-resolved unit ID from slug entry (set when slug was
	// built from DB institution names).
	if entry.unitID != "" {
		return entry.unitID
	}

	// Strategy 3: Name match using the original institution name.
	if entry.name != "" {
		if uid, ok := matcher.Match(entry.name); ok {
			return uid
		}
	}

	return ""
}

// buildSlugList creates the list of slugs to process, either from a file or
// from DB institution names.
func (b *bigfutureImporter) buildSlugList(ctx context.Context, pool *pgxpool.Pool) ([]slugEntry, error) {
	if b.slugFile != "" {
		return loadSlugFile(b.slugFile)
	}
	return buildSlugsFromDB(ctx, pool)
}

// loadSlugFile reads a file with one slug per line.
func loadSlugFile(path string) ([]slugEntry, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("open slug file: %w", err)
	}
	defer f.Close()

	var entries []slugEntry
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		slug := strings.TrimSpace(scanner.Text())
		if slug == "" || strings.HasPrefix(slug, "#") {
			continue
		}
		entries = append(entries, slugEntry{slug: slug})
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("read slug file: %w", err)
	}
	return entries, nil
}

// buildSlugsFromDB queries all institution names and converts them to BigFuture slugs.
func buildSlugsFromDB(ctx context.Context, pool *pgxpool.Pool) ([]slugEntry, error) {
	rows, err := pool.Query(ctx,
		`SELECT unit_id, institution_name FROM search_base.institution ORDER BY unit_id`)
	if err != nil {
		return nil, fmt.Errorf("query institutions: %w", err)
	}
	defer rows.Close()

	var entries []slugEntry
	for rows.Next() {
		var unitID, name string
		if err := rows.Scan(&unitID, &name); err != nil {
			return nil, fmt.Errorf("scan institution: %w", err)
		}
		slug := deadlines.SlugFromName(name)
		if slug == "" {
			continue
		}
		entries = append(entries, slugEntry{
			slug:   slug,
			name:   name,
			unitID: unitID,
		})
	}
	return entries, rows.Err()
}

// contentHash returns the hex-encoded SHA-256 hash of the given data.
func contentHash(data []byte) string {
	h := sha256.Sum256(data)
	return fmt.Sprintf("%x", h[:])
}
