  mockUser: { value: null as { id: string; email: string } | null },
}))

vi.mock('@/lib/posthog', () => ({
  posthog: { capture: mockCapture, identify: mockIdentify, reset: mockReset },
  posthogEnabled: true,
}))

vi.mock('react-router-dom', () => ({
  useLocation: () => ({ pathname: mockPathname.value }),
}))

vi.mock('@/stores/authStore', () => ({
  useAuthStore: (selector: (s: { user: typeof mockUser.value }) => unknown) =>
    selector({ user: mockUser.value }),
}))

describe('usePostHogPageview', () => {
  beforeEach(() => {
    mockCapture.mockClear()
    mockPathname.value = '/'
  })

  it('captures $pageview on mount', () => {
    renderHook(() => usePostHogPageview())
    expect(mockCapture).toHaveBeenCalledWith('$pageview', expect.objectContaining({
      $current_url: expect.any(String),
    }))
  })

  it('captures $pageview when pathname changes', () => {
    const { rerender } = renderHook(() => usePostHogPageview())
    mockCapture.mockClear()

    mockPathname.value = '/search'
    rerender()

    expect(mockCapture).toHaveBeenCalledWith('$pageview', expect.objectContaining({
      $current_url: expect.any(String),
    }))
  })
})

describe('usePostHogIdentify', () => {
  beforeEach(() => {
    mockIdentify.mockClear()
    mockReset.mockClear()
    mockUser.value = null
  })

  it('does not identify when user is null', () => {
    renderHook(() => usePostHogIdentify())
    expect(mockIdentify).not.toHaveBeenCalled()
    expect(mockReset).not.toHaveBeenCalled()
  })

  it('identifies when user becomes available', () => {
    mockUser.value = { id: 'user-123', email: 'test@example.com' }
    renderHook(() => usePostHogIdentify())
    expect(mockIdentify).toHaveBeenCalledWith('user-123', { email: 'test@example.com' })
  })

  it('resets when user becomes null after being identified', () => {
    mockUser.value = { id: 'user-123', email: 'test@example.com' }
    const { rerender } = renderHook(() => usePostHogIdentify())
    expect(mockIdentify).toHaveBeenCalledOnce()

    mockUser.value = null
    rerender()
    expect(mockReset).toHaveBeenCalledOnce()
  })

  it('does not re-identify the same user', () => {
    mockUser.value = { id: 'user-123', email: 'test@example.com' }
    const { rerender } = renderHook(() => usePostHogIdentify())
    expect(mockIdentify).toHaveBeenCalledOnce()

    rerender()
    expect(mockIdentify).toHaveBeenCalledOnce()
  })
})

